def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    inv_item = 1 / (item + 1e-6)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        complexity = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 3):
                        val = (ratio - a) ** 6 / (a * b * c * 0.95 + 1)
                        comp = val * np.tanh(ratio * b / (a + c))
                        complexity += comp
            complexity += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 2
            if bin_cap < item * 0.5:
                complexity += np.log1p(item**3 / (bin_cap + 0.5)) * 7
        elif 4 < ratio <= 7:
            for d in range(1, int(np.ceil(ratio)) + 5):
                for e in range(1, d + 4):
                    val = ((ratio - d) ** 4) * np.sin(ratio * d) / (e + 0.3)
                    complexity += np.tanh(val) * 1.7
            complexity += np.log(ratio) * 14 - np.tanh(ratio - 4) * 3
            if bin_cap > item * 3:
                complexity -= np.exp(-ratio) * 5
        elif 2 <= ratio <= 4:
            s = 0
            for f in range(1, 16):
                s += ((ratio - 2) ** f) / (f * 2.1) * np.cos(f * ratio * 1.2)
            complexity = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (4 - ratio)) * 2.1
            if (i * int(item)) % 7 == 0:
                complexity += np.sin(ratio * i) * 3
        elif 1 <= ratio < 2:
            s = 0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 2 + 1.2)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 1)) * 6
            else:
                penalty = np.cos(25 * ratio) * 3.5
            complexity = s + penalty + np.exp(-2 / (ratio + 0.02))
            for h in range(1, 6):
                complexity += np.sin(h * ratio * i * 1.1) * ((ratio - 1) ** h) / h
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3.5)
            complexity = s
            if (i + int(item * 2)) % 5 == 0:
                complexity *= np.log1p(bin_cap + 5) * 1.6
            else:
                complexity /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                complexity += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 1.1
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 15):
                s += ((0.5 - ratio) ** l) / (l * 2.7) * np.cos(l * ratio * 2.3)
            complexity = s + 2 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                complexity *= 3
            else:
                complexity /= 3.7
            if bin_cap < item * 0.3:
                complexity += np.log1p(item * bin_cap) * 5.5
            else:
                complexity -= np.exp(-ratio * 1.7) * 4.2
            for m in range(1, 9):
                complexity += ((0.5 - ratio) ** m) / (m * 9) * np.cos(item * m * 1.5)
        else:
            s = 0
            for n in range(1, 14):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.1)
            complexity = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                complexity *= 3.5
            else:
                complexity /= 2.8
            if bin_cap < item * 0.2:
                complexity += np.log1p(item * bin_cap) * 6.2
            else:
                complexity -= np.exp(-ratio * 3) * 5.1
            for o in range(1, 11):
                complexity += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 1.0)
        if bin_cap < item * 0.4:
            complexity += np.log1p(item ** 3 * bin_cap) * 7.2
        elif bin_cap > item * 3.5:
            complexity -= np.exp(-4 * ratio) * 6.1
        for p in range(1, 6):
            if (i + p * 2) % 5 == 0:
                complexity += np.sin(ratio * (i + p)) * 0.5
            else:
                complexity -= np.cos(ratio * (i + p)) * 0.5
        if i % 5 == 0:
            complexity += np.sin(ratio * i * 1.3) * 0.9
        else:
            complexity -= np.cos(ratio * i * 1.3) * 0.9
        complexity += np.tanh(np.sin(ratio * i) * np.cos(ratio * i * 1.5)) * 1.7
        if ratio > 3:
            for q in range(1, 4):
                complexity += (np.sin(q * ratio) * np.cos(q * i / (ratio + 0.5))) / q
        else:
            for r in range(1, 4):
                complexity -= (np.cos(r * ratio) * np.sin(r * i / (ratio + 0.3))) / (r + 0.5)
        priorities[i] = complexity
    return priorities
